import React, { useState } from 'react';
import './about.css'; // Make sure to create a CSS file for styling

const About = () => {
  const [activeIndex, setActiveIndex] = useState(null);

  const toggleDescription = (index) => {
    setActiveIndex(activeIndex === index ? null : index);
  };

  return (
    <div className="about-container">
      <div className="name-job">
        <h1>Your Name</h1>
        <h2>Your Job Title</h2>
      </div>
      <div className="self-message">
        <p>A small self message for good promotion</p>
      </div>
      <div className="image-container">
        <img src="your-image-url.jpg" alt="Your Name" />
      </div>
      <div className="bullet-points">
        {[...Array(5)].map((_, index) => (
          <div key={index} className="bullet-point">
            <h3 onClick={() => toggleDescription(index)}>
              Bullet Point Title {index + 1}
            </h3>
            {activeIndex === index && (
              <p className="description">
                This is the description for bullet point {index + 1}.
              </p>
            )}
          </div>
        ))}
      </div>
    </div>
  );
};

export default About;
